public class Validator {

    public boolean isValid(String input) {
        if (input != null) {
            if (!input.isEmpty()) {
                if (input.length() >= 3) {
                    if (input.length() <= 100) {
                        if (input.matches("[a-zA-Z0-9]+")) {
                            return true;
                        }
                    }
                }
            }
        }
        return false;
    }
}
